import React, { Component } from 'react';
import './SNSLink.css';

class SNSLink extends Component {

    getSrc = (props) => {
        if (props.type == "github") {
            return "./github.png"
        }
        else{
            return ""
        }
    }

    render() {
        const {
            type,
            id,
            link,
            src
        } = this.props;

        if (type == "github") {
            const {
                link = "https://github.com/" + id,
                src = "./github.png"
            } = this.props;
            console.log(type);
        }
        else{
            console.log(type);
        }

        const openWindow = () => {
            window.open(link, '_blank');
        }

        return (
            <button className="SNSBtn" onClick={openWindow}>
                <img className="logo" src={this.getSrc(type)}></img>
            </button>
        );
    }
}

export default SNSLink;
